export function AuthProvider({ children }: AuthProviderProps) {
  const [tenants, setTenants] = useState<Tenant[]>([])

  async function switchTenant(tenantId: string) {
    // Request new token with different X-Tenant-ID
    const response = await api.post('/api/v1/auth/switch-tenant', { tenant_id: tenantId })
    const { access_token } = response.data

    // Store new token
    localStorage.setItem('access_token', access_token)

    // Refresh user data
    await refreshUser()
  }

  // Fetch user's tenants on login
  useEffect(() => {
    if (authState.isAuthenticated) {
      api.get('/api/v1/users/me/tenants').then(r => setTenants(r.data))
    }
  }, [authState.isAuthenticated])
}
```

