export function ImpersonateBanner() {
  const { user } = useAuth()

  // Check if token has impersonating claim
  const isImpersonating = useMemo(() => {
    const tokens = getAuthTokens()
    if (!tokens) return false
    const decoded = jwtDecode(tokens.access_token)
    return decoded.impersonating === true
  }, [user])

  if (!isImpersonating) return null

  return (
    <div className="bg-yellow-500 text-yellow-900 px-4 py-2 text-center font-semibold">
      ⚠️ You are impersonating {user?.current_tenant?.name}
      <Button variant="link" onClick={exitImpersonation}>Exit Impersonation</Button>
    </div>
  )
}
